export default function handler(req, res) {
  if (req.method === 'GET') {
    // Simulate fetching posts
    const posts = [
      { id: 1, title: 'First Post', content: 'This is the first post' },
      { id: 2, title: 'Second Post', content: 'This is the second post' }
    ];

    res.status(200).json(posts);
  } else if (req.method === 'POST') {
    const { title, content } = req.body;

    if (!title || !content) {
      return res.status(400).json({ error: 'Title and content are required' });
    }

    // Simulate creating a post
    const newPost = {
      id: Date.now(),
      title,
      content,
      createdAt: new Date().toISOString()
    };

    res.status(201).json(newPost);
  } else {
    res.setHeader('Allow', ['GET', 'POST']);
    res.status(405).end(`Method ${req.method} Not Allowed`);
  }
}

import Head from 'next/head';
import { useRouter } from 'next/router';

export async function getServerSideProps({ req }) {
  const userAgent = req.headers['user-agent'] || '';
  const posts = await fetch('https://jsonplaceholder.typicode.com/posts?_limit=5')
    .then(res => res.json());

  return {
    props: {
      posts,
      userAgent,
      timestamp: new Date().toISOString()
    }
  };
}

export default function HomePage({ posts, userAgent, timestamp }) {
  const router = useRouter();

  const navigateToBlog = () => {
    router.push('/blog');
  };

  return (
    <>
      <Head>
        <title>Home - My Blog</title>
        <meta name="description" content="Welcome to my blog homepage" />
        <meta property="og:title" content="Home - My Blog" />
      </Head>

      <div>
        <h1>Welcome to My Blog</h1>
        <p>Server-side rendered at: {timestamp}</p>
        <p>Your user agent: {userAgent}</p>

        <h2>Recent Posts</h2>
        <ul>
          {posts.map(post => (
            <li key={post.id}>
              <a href={`/blog/${post.id}`}>{post.title}</a>
            </li>
          ))}
        </ul>

        <button onClick={navigateToBlog}>
          View All Posts
        </button>
      </div>
    </>
  );
}

export default function handler(req, res) {
  const { id } = req.query;

  if (req.method === 'GET') {
    // Simulate fetching a single post
    const post = {
      id: parseInt(id),
      title: `Post ${id}`,
      content: `This is the content for post ${id}`,
      createdAt: new Date().toISOString()
    };

    res.status(200).json(post);
  } else if (req.method === 'PUT') {
    const { title, content } = req.body;

    // Simulate updating a post
    const updatedPost = {
      id: parseInt(id),
      title: title || `Post ${id}`,
      content: content || `Updated content for post ${id}`,
      updatedAt: new Date().toISOString()
    };

    res.status(200).json(updatedPost);
  } else if (req.method === 'DELETE') {
    // Simulate deleting a post
    res.status(200).json({ message: `Post ${id} deleted successfully` });
  } else {
    res.setHeader('Allow', ['GET', 'PUT', 'DELETE']);
    res.status(405).end(`Method ${req.method} Not Allowed`);
  }
}

---
title: generateStaticParams
description: API reference for the generateStaticParams function.
---

The `generateStaticParams` function can be used in combination with [dynamic route segments](/docs/app/api-reference/file-conventions/dynamic-routes) to [**statically generate**](/docs/app/guides/caching#static-rendering) routes at build time instead of on-demand at request time.

`generateStaticParams` can be used with:

- [Pages](/docs/app/api-reference/file-conventions/page) (`page.tsx`/`page.js`)
- [Layouts](/docs/app/api-reference/file-conventions/layout) (`layout.tsx`/`layout.js`)
- [Route Handlers](/docs/app/api-reference/file-conventions/route) (`route.ts`/`route.js`)

```tsx filename="app/blog/[slug]/page.tsx" switcher
// Return a list of `params` to populate the [slug] dynamic segment
export async function generateStaticParams() {
  const posts = await fetch('https://.../posts').then((res) => res.json())

  return posts.map((post) => ({
    slug: post.slug,
  }))
}

// Multiple versions of this page will be statically generated
// using the `params` returned by `generateStaticParams`
export default async function Page({
  params,
}: {
  params: Promise<{ slug: string }>
}) {
  const { slug } = await params
  // ...
}
```

